Fetch build timeline - all stages/jobs/tasks with pass/fail status: TOKEN=$(az account get-access-token --resource 499b84ac-1321-427f-aa17-267ca6975798 --query accessToken -o tsv 2>/dev/null) && curl -s -H "Authorization: Bearer $TOKEN" "https://office.visualstudio.com/e853b87d-318c-4879-bedc-5855f3483b54/_apis/build/builds/46057316/Timeline?api-version=7.1" | node -e "
const chunks = [];
process.stdin.on('data', d => chunks.push(d));
process.stdin.on('end', () => {
  const data = JSON.parse(Buffer.concat(chunks));
  const records = data.records || [];
  // Show all records with their result/state
  records.forEach(r => {
    if (r.type === 'Stage' || r.type === 'Job' || r.type === 'Task') {
      const icon = r.result === 'succeeded' ? 'PASS' : r.result === 'failed' ? 'FAIL' : r.result === 'skipped' ? 'SKIP' : r.state || r.result || '???';
      console.log(icon.padEnd(10), r.type.padEnd(6), r.name);
      if (r.result === 'failed' && r.issues && r.issues.length > 0) {
        r.issues.forEach(i => console.log('           ERROR:', i.message?.substring(0, 200)));
      }
    }
  });
});
"

Fetch test runs associated with this build: TOKEN=$(az account get-access-token --resource 499b84ac-1321-427f-aa17-267ca6975798 --query accessToken -o tsv 2>/dev/null) && curl -s -H "Authorization: Bearer $TOKEN" "https://office.visualstudio.com/OC/_apis/test/runs?buildUri=vstfs:///Build/Build/46057316&api-version=7.1" | node -e "
const chunks = [];
